    let tryFind (name: string) : UnitSummary option =
        all |> List.tryFind (fun u -> u.name = name)

    let builders () = all |> List.filter (fun u -> u.isBuilder)
    let armed () = all |> List.filter (fun u -> u.isArmed)
    let mobile () = all |> List.filter (fun u -> u.isMobile)
    let flying () = all |> List.filter (fun u -> u.canFly)
    let economy () = all |> List.filter (fun u -> u.hasEconomy)
    let buildings () = all |> List.filter (fun u -> u.isBuilding)
